1	// Account — framework-free (TC-PURE-01). v1 is single-user, UAH-only
2	// (BC-SCOPE-01/02). Accounts store NO opening balance: account balance is derived
3	// only from non-deleted ledger items (FR-ACCT-06, FR-LEDGER-05).
4	
5	import type { Currency } from "./money";
6	
7	/** Seeded default account name so item creation works on a clean checkout (FR-ACCT-06). */
8	export const CASH_ACCOUNT_NAME = "Готівка" as const;
9	
10	/** Upper bound on an account name (after trimming). */
11	export const MAX_ACCOUNT_NAME_LENGTH = 60;
12	
13	export interface Account {
14	  id: string;
15	  name: string;
16	  currency: Currency;
17	  /** Exactly one active account is the default (FR-ACCT-01). */
18	  isDefault: boolean;
19	  /** Soft-archive marker; null while active (FR-ACCT-05). No hard delete. */
20	  archivedAt: Date | null;
21	  createdAt: Date;
22	}
23	
24	export interface NewAccount {
25	  id?: string;
26	  name: string;
27	  isDefault?: boolean;
28	}
29	
30	/** Stable codes for account errors; the UI maps each to Ukrainian copy. */
31	export type AccountErrorCode =
32	  | "name-required"
33	  | "name-too-long"
34	  | "not-found"
35	  | "cannot-archive-default"
36	  | "cannot-archive-last";
37	
38	/** A rejected account operation, carrying a stable `code` for the error surface. */
39	export class AccountError extends Error {
40	  constructor(
41	    readonly code: AccountErrorCode,
42	    message: string,
43	  ) {
44	    super(message);
45	    this.name = "AccountError";
46	  }
47	}
48	
49	/** Is this account soft-archived (hidden from active list + default selection)? */
50	export function isArchived(account: Account): boolean {
51	  return account.archivedAt !== null;
52	}
53	
54	/**
55	 * Validates and normalizes an account name: trims, rejects empty/whitespace and
56	 * over-long names (FR-ACCT-03/04). Returns the cleaned name.
57	 */
58	export function validateAccountName(raw: string): string {
